class Solution {
    int ans=0;
    void dfs(int r,int n,vector<bool>& col,vector<bool>& d1,vector<bool>& d2){
        if(r==n){ ans++; return; }
        for(int c=0;c<n;c++){
            if(col[c]||d1[r-c+n]||d2[r+c]) continue;
            col[c]=d1[r-c+n]=d2[r+c]=true;
            dfs(r+1,n,col,d1,d2);
            col[c]=d1[r-c+n]=d2[r+c]=false;
        }
    }
public:
    int totalNQueens(int n){
        vector<bool> col(n),d1(2*n),d2(2*n);
        dfs(0,n,col,d1,d2); return ans;
    }
};
